digraph starmap {
    rankdir=TB;
    compound=true;
    node [fontname="Helvetica", fontsize=10];
    edge [fontname="Helvetica", fontsize=9];

    subgraph cluster_no_module {
        label="(no module)";
        style="rounded,filled";
        fillcolor="#fafafa";
        color="#999999";
        fontsize=11;

        "example:galileo_v0_5::context" [label="context", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::thought_experiment_setup" [label="thought_experiment_setup", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::vacuum_setup" [label="vacuum_setup", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::daily_observation" [label="★ daily_observation\n(0.90 → 0.96)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::aristotle_model" [label="★ aristotle_model\n(0.01)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::medium_model" [label="★ medium_model\n(0.64)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::aristotle_daily_prediction" [label="★ aristotle_daily_prediction\n(0.96)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::_anon_000" [label="\n(0.50)", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::aristotle_daily_match" [label="★ aristotle_daily_match\n(1.00)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::medium_daily_prediction" [label="★ medium_daily_prediction\n(0.96)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::_anon_001" [label="\n(0.50)", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::medium_daily_match" [label="★ medium_daily_match\n(1.00)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::composite_faster" [label="★ composite_faster\n(0.34)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::_anon_002" [label="\n(0.50)", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::composite_slower" [label="★ composite_slower\n(0.34)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::_anon_003" [label="\n(0.50)", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "example:galileo_v0_5::aristotle_paradox" [label="★ aristotle_paradox\n(1.00)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::vacuum_equal_fall_prediction" [label="★ vacuum_equal_fall_prediction\n(0.82)", shape=box, style=filled, fillcolor="#d4edda", color="#28a745", penwidth=2];
        "example:galileo_v0_5::_anon_004" [label="\n(0.50)", shape=box, style=filled, fillcolor="#ddeeff", color="#4488bb"];
        "strat_0" [label="deduction", shape=ellipse, style=filled, fillcolor="#fff9c4", color="#f9a825"];
        "strat_1" [label="deduction", shape=ellipse, style=filled, fillcolor="#fff9c4", color="#f9a825"];
        "strat_2" [label="deduction", shape=ellipse, style=filled, fillcolor="#fff9c4", color="#f9a825"];
        "strat_3" [label="deduction", shape=ellipse, style=filled, fillcolor="#fff9c4", color="#f9a825"];
        "strat_4" [label="deduction", shape=ellipse, style=filled, fillcolor="#fff9c4", color="#f9a825"];
        "oper_0" [label="⊙ equivalence", shape=hexagon, style=filled, fillcolor="#f5f5f7", color="#a8a8b8"];
        "oper_1" [label="⊙ equivalence", shape=hexagon, style=filled, fillcolor="#f5f5f7", color="#a8a8b8"];
        "oper_2" [label="⊗ contradiction", shape=hexagon, style=filled, fillcolor="#ffebee", color="#c62828"];
    }

    // edges
    "example:galileo_v0_5::aristotle_model" -> "strat_0" [penwidth=1.0];
    "strat_0" -> "example:galileo_v0_5::aristotle_daily_prediction" [penwidth=1.2];
    "example:galileo_v0_5::medium_model" -> "strat_1" [penwidth=1.0];
    "strat_1" -> "example:galileo_v0_5::medium_daily_prediction" [penwidth=1.2];
    "example:galileo_v0_5::aristotle_model" -> "strat_2" [penwidth=1.0];
    "example:galileo_v0_5::thought_experiment_setup" -> "strat_2" [style=dashed, penwidth=0.8, color="#888888"];
    "strat_2" -> "example:galileo_v0_5::composite_faster" [penwidth=1.2];
    "example:galileo_v0_5::aristotle_model" -> "strat_3" [penwidth=1.0];
    "example:galileo_v0_5::thought_experiment_setup" -> "strat_3" [style=dashed, penwidth=0.8, color="#888888"];
    "strat_3" -> "example:galileo_v0_5::composite_slower" [penwidth=1.2];
    "example:galileo_v0_5::medium_model" -> "strat_4" [penwidth=1.0];
    "example:galileo_v0_5::vacuum_setup" -> "strat_4" [style=dashed, penwidth=0.8, color="#888888"];
    "strat_4" -> "example:galileo_v0_5::vacuum_equal_fall_prediction" [penwidth=1.2];
    "example:galileo_v0_5::aristotle_daily_prediction" -> "oper_0" [penwidth=1.0];
    "example:galileo_v0_5::daily_observation" -> "oper_0" [penwidth=1.0];
    "oper_0" -> "example:galileo_v0_5::aristotle_daily_match" [penwidth=1.2];
    "example:galileo_v0_5::medium_daily_prediction" -> "oper_1" [penwidth=1.0];
    "example:galileo_v0_5::daily_observation" -> "oper_1" [penwidth=1.0];
    "oper_1" -> "example:galileo_v0_5::medium_daily_match" [penwidth=1.2];
    "example:galileo_v0_5::composite_faster" -> "oper_2" [dir=none, color="#d32f2f", penwidth=1.4];
    "example:galileo_v0_5::composite_slower" -> "oper_2" [dir=none, color="#d32f2f", penwidth=1.4];
    "oper_2" -> "example:galileo_v0_5::aristotle_paradox" [dir=none, color="#d32f2f", penwidth=1.4];
